document.addEventListener('DOMContentLoaded',()=>{const mainImage=document.getElementById('mainProductImage');const productInfo=document.getElementById('productDetailInfo');const defaultImage=productInfo?.dataset.defaultImage??'';document.querySelectorAll('.product-detail-variation-row[data-image]').forEach((row)=>{const preview=()=>{if(mainImage&&mainImage.tagName==='IMG'&&row.dataset.image){mainImage.src=row.dataset.image;}};row.addEventListener('mouseenter',preview);row.addEventListener('focusin',preview);});document.getElementById('detailVariations')?.addEventListener('mouseleave',()=>{if(mainImage&&mainImage.tagName==='IMG'&&defaultImage){mainImage.src=defaultImage;}});});